#include<bits/stdc++.h>
#define ll long long
#define PII pair<int,int>
#define mk make_pair
#define inf 0x3f3f3f3f
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a:b)
#define Yes puts("Yes")
#define No puts("No")
#define llinf 0x3f3f3f3f3f3f3f3f
#define snd second
#define fst first
#define il inline
#define pb push_back
#define CI const int
#define cl(x) memset(x,0,sizeof x)
#define cli(x) memset(x,0x3f,sizeof x)
#define lowbit(x) (x&(-x))
#define wh while
#define gc() getchar()
#define pc(x) putchar(x)
#define NP namespace
#define ls (k<<1)
#define rs (k<<1|1)
#define mid ((l+r)>>1)
using NP std;
NP phigrOS{
	il ll read(){
		ll x=0,f=1;char ch=gc();
		wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=gc();}
		wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
		return x*f;
	}
	void write(ll x){
		if(x<0)pc('-'),x=-x;
		if(x>9)write(x/10);
		pc(x%10+'0');
	}
	void writeln(ll x){
		write(x);
		puts("");
	}
}
using NP phigrOS;
int m,n,k,cnt;
double mx;
int can[10000005];
int f[10000005];
struct P{int x,y;}a[10000005];
struct E{int u,v;double w;}b[10000005];
bool cmp(E a,E b){return a.w<b.w;}
int ff(int x){return f[x]==x?x:f[x]=ff(f[x]);}
signed main(){
	m=read();
	FOR(i,1,m)can[i]=read();
	n=read();
	FOR(i,1,n){a[i].x=read();a[i].y=read();}
	FOR(i,1,n){
		FOR(j,1,n){
			if(i==j)continue;
			b[++k]={i,j,sqrt(1.0*(a[i].x-a[j].x)*(a[i].x-a[j].x)+1.0*(a[i].y-a[j].y)*(a[i].y-a[j].y))};
		}
	}
	sort(b+1,b+k+1,cmp);
	FOR(i,1,n)f[i]=i;
	FOR(i,1,k){
		int u=b[i].u,v=b[i].v;
		double w=b[i].w;
		int x=ff(u),y=ff(v);
		if(x!=y){
			cnt++;
			mx=max(mx,w);
			f[x]=y;
		}
		if(cnt==n-1)break;
	}
	int ans=0;
	FOR(i,1,m){
		if(can[i]>=mx)ans++;
	}
	write(ans);
	return 0;
}
